type ConvexEmail struct {
	ExternalID  string  `json:"externalId"`
	Source      string  `json:"source"`
	Direction   string  `json:"direction"`
	ThreadID    string  `json:"threadId"`
	Subject     string  `json:"subject"`
	FromEmail   string  `json:"fromEmail"`
	ToEmails    string  `json:"toEmails"`
	CcEmails    string  `json:"ccEmails"`
	Date        string  `json:"date"`
	Snippet     string  `json:"snippet"`
	SyncVersion float64 `json:"syncVersion"`
}

// SyncEmailsResponse is returned by /api/sync-emails.
type SyncEmailsResponse struct {
	Emails []ConvexEmail `json:"emails"`
	Count  int           `json:"count"`
	Error  string        `json:"error,omitempty"`
}

// SyncEmails fetches emails from Convex newer than afterVersion.
func (c *ConvexClient) SyncEmails(token string, afterVersion float64) (*SyncEmailsResponse, error) {
	body, _ := json.Marshal(map[string]float64{"afterVersion": afterVersion})
	httpReq, err := http.NewRequest("POST", c.baseURL+"/api/sync-emails", bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling sync-emails: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result SyncEmailsResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}
	if result.Error != "" {
		return nil, fmt.Errorf("%s", result.Error)
	}
	return &result, nil
}

