 40→Reuses `findUserByToken` from `sendApi.ts` and `findUnipileAccount` from `sendApi.ts` (already defined there). Defines three httpAction handlers.
 41→
 42→```typescript
 43→// convex/connect.ts
 44→import { v } from "convex/values";
 45→import { httpAction, internalQuery } from "./_generated/server";
 46→import { api, internal } from "./_generated/api";
 47→
 48→function jsonResponse(data: any, status = 200) {
 49→  return new Response(JSON.stringify(data), {
 50→    status,
 51→    headers: { "Content-Type": "application/json" },
 52→  });
 53→}
 54→
 55→async function authenticateRequest(ctx: any, request: Request) {
 56→  const authHeader = request.headers.get("Authorization");
 57→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 58→    return { error: jsonResponse({ error: "Missing auth token" }, 401) };
 59→  }
 60→  const token = authHeader.slice(7);
 61→  const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 62→  if (!user) {
 63→    return { error: jsonResponse({ error: "Invalid auth token" }, 401) };
 64→  }
 65→  return { user };
 66→}
 67→
 68→// POST /api/connect-gmail — returns Unipile hosted auth URL for Gmail
 69→export const connectGmail = httpAction(async (ctx, request) => {
 70→  try {
 71→    const auth = await authenticateRequest(ctx, request);
 72→    if (auth.error) return auth.error;
 73→    const user = auth.user!;
 74→
 75→    // Check if already connected
 76→    const existing = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 77→      userId: user._id,
 78→      provider: "GOOGLE",
 79→    });
 80→    if (existing && existing.status === "connected") {
 81→      return jsonResponse({ already_connected: true, email: existing.email });
 82→    }
 83→
 84→    // Get Unipile hosted auth link
 85→    const result = await ctx.runAction(api.unipile.requestConnectionLink, {
 86→      userId: user._id,
 87→      provider: "GOOGLE",
 88→    });
 89→
 90→    return jsonResponse({ url: result.url });
 91→  } catch (error: any) {
 92→    console.error("connect-gmail error:", error);
 93→    return jsonResponse({ error: error.message }, 500);
 94→  }
 95→});
 96→
 97→// GET /api/connection-status — CLI polls this after opening auth URL
 98→export const connectionStatus = httpAction(async (ctx, request) => {
 99→  try {
100→    const auth = await authenticateRequest(ctx, request);
101→    if (auth.error) return auth.error;
102→    const user = auth.user!;
103→
104→    const account = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
105→      userId: user._id,
106→      provider: "GOOGLE",
107→    });
108→
109→    if (!account) {
110→      return jsonResponse({ connected: false });
111→    }
112→
113→    return jsonResponse({
114→      connected: account.status === "connected",
115→      email: account.email || "",
116→      status: account.status,
117→    });
118→  } catch (error: any) {
119→    return jsonResponse({ error: error.message }, 500);
120→  }
121→});
122→
123→// POST /api/sync-emails — CLI fetches emails from Convex (backfilled from Unipile)
124→export const syncEmails = httpAction(async (ctx, request) => {
125→  try {
126→    const auth = await authenticateRequest(ctx, request);
127→    if (auth.error) return auth.error;
128→    const user = auth.user!;
129→
130→    const payload = await request.json().catch(() => ({}));
131→    const afterVersion = payload.afterVersion ?? 0;
132→
133→    const emails = await ctx.runQuery(internal.connect.listEmailsAfterVersion, {
134→      userId: user._id,
135→      afterVersion,
136→    });
137→
138→    return jsonResponse({ emails, count: emails.length });
139→  } catch (error: any) {
140→    return jsonResponse({ error: error.message }, 500);
141→  }
142→});
143→
144→// --- Internal queries for sync-emails ---
145→
146→export const listEmailsAfterVersion = internalQuery({
147→  args: {
148→    userId: v.string(),
149→    afterVersion: v.float64(),
150→  },
151→  handler: async (ctx, args) => {
152→    // Use by_sync_version index for efficient filtering
153→    const allEmails = await ctx.db
154→      .query("emails")
155→      .withIndex("by_sync_version")
156→      .collect();
157→    // Filter by user and version (index gives us version ordering)
158→    return allEmails
159→      .filter(
160→        (e) =>
161→          e.userId === args.userId && e.syncVersion > args.afterVersion
162→      )
163→      .slice(0, 500);
164→  },
165→});
166→```
