### Task 2: Convex — Async Backfill on Account Callback

**Files:**
- Modify: `convex/webhook.ts:103-127`

The key fix: use `ctx.scheduler.runAfter(0, ...)` to schedule backfill asynchronously. The backfill can take minutes for large mailboxes, and httpActions have a 2-minute timeout.

- [ ] **Step 1: Schedule async backfill after account registration**

```typescript
// In convex/webhook.ts — add import at top:
import { api } from "./_generated/api";

// Replace the unipileAccountCallback handler:
export const unipileAccountCallback = httpAction(async (ctx, request) => {
  try {
    const payload = await request.json();
    const accountId = payload.account_id || "";
    const userId = payload.name || "";
    const email = payload.identifier || "";

    if (!accountId || !userId) {
      return new Response("Missing account_id or name", { status: 400 });
    }

    await ctx.runMutation(internal.webhook.registerUnipileAccount, {
      userId,
      unipileAccountId: accountId,
      provider: "GOOGLE",
      email,
    });

    // Schedule backfill asynchronously (can take minutes for large mailboxes)
    await ctx.scheduler.runAfter(0, api.unipile.backfillEmails, {
      userId,
      unipileAccountId: accountId,
    });

    return new Response("OK", { status: 200 });
  } catch (error: any) {
    console.error("Account callback error:", error);
    return new Response("Internal error", { status: 500 });
  }
});
```

